1	import type { ParamIndexMap, Router } from '../../router'
2	import {
3	  MESSAGE_MATCHER_IS_ALREADY_BUILT,
4	  METHOD_NAME_ALL,
5	  UnsupportedPathError,
6	} from '../../router'
7	import { checkOptionalParameter } from '../../utils/url'
8	import type { HandlerData, StaticMap, Matcher, MatcherMap } from './matcher'
9	import { match, emptyParam } from './matcher'
10	import { PATH_ERROR } from './node'
11	import type { ParamAssocArray } from './node'
12	import { Trie } from './trie'
13	
14	type HandlerWithMetadata<T> = [T, number] // [handler, paramCount]
15	
16	// eslint-disable-next-line @typescript-eslint/no-explicit-any
17	const nullMatcher: Matcher<any> = [/^$/, [], Object.create(null)]
18	
19	let wildcardRegExpCache: Record<string, RegExp> = Object.create(null)
20	function buildWildcardRegExp(path: string): RegExp {
21	  return (wildcardRegExpCache[path] ??= new RegExp(
22	    path === '*'
23	      ? ''
24	      : `^${path.replace(/\/\*$|([.\\+*[^\]$()])/g, (_, metaChar) =>
25	          metaChar ? `\\${metaChar}` : '(?:|/.*)'
26	        )}$`
27	  ))
28	}
29	
30	function clearWildcardRegExpCache() {
31	  wildcardRegExpCache = Object.create(null)
32	}
33	
34	function buildMatcherFromPreprocessedRoutes<T>(
35	  routes: [string, HandlerWithMetadata<T>[]][]
36	): Matcher<T> {
37	  const trie = new Trie()
38	  const handlerData: HandlerData<T>[] = []
39	  if (routes.length === 0) {
40	    return nullMatcher
41	  }
42	
43	  const routesWithStaticPathFlag = routes
44	    .map(
45	      (route) => [!/\*|\/:/.test(route[0]), ...route] as [boolean, string, HandlerWithMetadata<T>[]]
46	    )
47	    .sort(([isStaticA, pathA], [isStaticB, pathB]) =>
48	      isStaticA ? 1 : isStaticB ? -1 : pathA.length - pathB.length
49	    )
50	
51	  const staticMap: StaticMap<T> = Object.create(null)
52	  for (let i = 0, j = -1, len = routesWithStaticPathFlag.length; i < len; i++) {
53	    const [pathErrorCheckOnly, path, handlers] = routesWithStaticPathFlag[i]
54	    if (pathErrorCheckOnly) {
55	      staticMap[path] = [handlers.map(([h]) => [h, Object.create(null)]), emptyParam]
56	    } else {
57	      j++
58	    }
59	
60	    let paramAssoc: ParamAssocArray
61	    try {
62	      paramAssoc = trie.insert(path, j, pathErrorCheckOnly)
63	    } catch (e) {
64	      throw e === PATH_ERROR ? new UnsupportedPathError(path) : e
65	    }
66	
67	    if (pathErrorCheckOnly) {
68	      continue
69	    }
70	
71	    handlerData[j] = handlers.map(([h, paramCount]) => {
72	      const paramIndexMap: ParamIndexMap = Object.create(null)
73	      paramCount -= 1
74	      for (; paramCount >= 0; paramCount--) {
75	        const [key, value] = paramAssoc[paramCount]
76	        paramIndexMap[key] = value
77	      }
78	      return [h, paramIndexMap]
79	    })
80	  }
81	
82	  const [regexp, indexReplacementMap, paramReplacementMap] = trie.buildRegExp()
83	  for (let i = 0, len = handlerData.length; i < len; i++) {
84	    for (let j = 0, len = handlerData[i].length; j < len; j++) {
85	      const map = handlerData[i][j]?.[1]
86	      if (!map) {
87	        continue
88	      }
89	      const keys = Object.keys(map)
90	      for (let k = 0, len = keys.length; k < len; k++) {
91	        map[keys[k]] = paramReplacementMap[map[keys[k]]]
92	      }
93	    }
94	  }
95	
96	  const handlerMap: HandlerData<T>[] = []
97	  // using `in` because indexReplacementMap is a sparse array
98	  for (const i in indexReplacementMap) {
99	    handlerMap[i] = handlerData[indexReplacementMap[i]]
100	  }
101	
102	  return [regexp, handlerMap, staticMap] as Matcher<T>
103	}
104	
105	function findMiddleware<T>(
106	  middleware: Record<string, T[]> | undefined,
107	  path: string
108	): T[] | undefined {
109	  if (!middleware) {
110	    return undefined
111	  }
112	
113	  for (const k of Object.keys(middleware).sort((a, b) => b.length - a.length)) {
114	    if (buildWildcardRegExp(k).test(path)) {
115	      return [...middleware[k]]
116	    }
117	  }
118	
119	  return undefined
120	}
121	
122	export class RegExpRouter<T> implements Router<T> {
123	  name: string = 'RegExpRouter'
124	  #middleware?: Record<string, Record<string, HandlerWithMetadata<T>[]>>
125	  #routes?: Record<string, Record<string, HandlerWithMetadata<T>[]>>
126	
127	  constructor() {
128	    this.#middleware = { [METHOD_NAME_ALL]: Object.create(null) }
129	    this.#routes = { [METHOD_NAME_ALL]: Object.create(null) }
130	  }
131	
132	  add(method: string, path: string, handler: T) {
133	    const middleware = this.#middleware
134	    const routes = this.#routes
135	
136	    if (!middleware || !routes) {
137	      throw new Error(MESSAGE_MATCHER_IS_ALREADY_BUILT)
138	    }
139	
140	    if (!middleware[method]) {
141	      ;[middleware, routes].forEach((handlerMap) => {
142	        handlerMap[method] = Object.create(null)
143	        Object.keys(handlerMap[METHOD_NAME_ALL]).forEach((p) => {
144	          handlerMap[method][p] = [...handlerMap[METHOD_NAME_ALL][p]]
145	        })
146	      })
147	    }
148	
149	    if (path === '/*') {
150	      path = '*'
151	    }
152	
153	    const paramCount = (path.match(/\/:/g) || []).length
154	
155	    if (/\*$/.test(path)) {
156	      const re = buildWildcardRegExp(path)
157	      if (method === METHOD_NAME_ALL) {
158	        Object.keys(middleware).forEach((m) => {
159	          middleware[m][path] ||=
160	            findMiddleware(middleware[m], path) ||
161	            findMiddleware(middleware[METHOD_NAME_ALL], path) ||
162	            []
163	        })
164	      } else {
165	        middleware[method][path] ||=
166	          findMiddleware(middleware[method], path) ||
167	          findMiddleware(middleware[METHOD_NAME_ALL], path) ||
168	          []
169	      }
170	      Object.keys(middleware).forEach((m) => {
171	        if (method === METHOD_NAME_ALL || method === m) {
172	          Object.keys(middleware[m]).forEach((p) => {
173	            re.test(p) && middleware[m][p].push([handler, paramCount])
174	          })
175	        }
176	      })
177	
178	      Object.keys(routes).forEach((m) => {
179	        if (method === METHOD_NAME_ALL || method === m) {
180	          Object.keys(routes[m]).forEach(
181	            (p) => re.test(p) && routes[m][p].push([handler, paramCount])
182	          )
183	        }
184	      })
185	
186	      return
187	    }
188	
189	    const paths = checkOptionalParameter(path) || [path]
190	    for (let i = 0, len = paths.length; i < len; i++) {
191	      const path = paths[i]
192	
193	      Object.keys(routes).forEach((m) => {
194	        if (method === METHOD_NAME_ALL || method === m) {
195	          routes[m][path] ||= [
196	            ...(findMiddleware(middleware[m], path) ||
197	              findMiddleware(middleware[METHOD_NAME_ALL], path) ||
198	              []),
199	          ]
200	          routes[m][path].push([handler, paramCount - len + i + 1])
201	        }
202	      })
203	    }
204	  }
205	
206	  match: typeof match<Router<T>, T> = match
207	
208	  protected buildAllMatchers(): MatcherMap<T> {
209	    const matchers: MatcherMap<T> = Object.create(null)
210	
211	    Object.keys(this.#routes!)
212	      .concat(Object.keys(this.#middleware!))
213	      .forEach((method) => {
214	        matchers[method] ||= this.#buildMatcher(method)
215	      })
216	
217	    // Release cache
218	    this.#middleware = this.#routes = undefined
219	    clearWildcardRegExpCache()
220	
221	    return matchers
222	  }
223	
224	  #buildMatcher(method: string): Matcher<T> | null {
225	    const routes: [string, HandlerWithMetadata<T>[]][] = []
226	
227	    let hasOwnRoute = method === METHOD_NAME_ALL
228	
229	    ;[this.#middleware!, this.#routes!].forEach((r) => {
230	      const ownRoute = r[method]
231	        ? Object.keys(r[method]).map((path) => [path, r[method][path]])
232	        : []
233	      if (ownRoute.length !== 0) {
234	        hasOwnRoute ||= true
235	        routes.push(...(ownRoute as [string, HandlerWithMetadata<T>[]][]))
236	      } else if (method !== METHOD_NAME_ALL) {
237	        routes.push(
238	          ...(Object.keys(r[METHOD_NAME_ALL]).map((path) => [path, r[METHOD_NAME_ALL][path]]) as [
239	            string,
240	            HandlerWithMetadata<T>[],
241	          ][])
242	        )
243	      }
244	    })
