47	  #varIndex?: number
48	  #children: Record<string, Node> = Object.create(null)
49	
50	  insert(
51	    tokens: readonly string[],
52	    index: number,
53	    paramMap: ParamAssocArray,
54	    context: Context,
55	    pathErrorCheckOnly: boolean
56	  ): void {
57	    if (tokens.length === 0) {
58	      if (this.#index !== undefined) {
59	        throw PATH_ERROR
60	      }
61	      if (pathErrorCheckOnly) {
62	        return
63	      }
64	
65	      this.#index = index
66	      return
67	    }
68	
69	    const [token, ...restTokens] = tokens
70	    const pattern =
71	      token === '*'
72	        ? restTokens.length === 0
73	          ? ['', '', ONLY_WILDCARD_REG_EXP_STR] // '*' matches to all the trailing paths
74	          : ['', '', LABEL_REG_EXP_STR]
